mapper.sql:
from aiw_investment_feedback f
where 1 = 1

    and f.user_biz_id = #{criteria.userBizId}


    and f.target_type = #{criteria.targetType}


    and f.target_biz_id = #{criteria.targetBizId}


    and f.report_biz_id = #{criteria.reportBizId}


    and f.prompt_code = #{criteria.promptCode}


    and f.prompt_version = #{criteria.promptVersion}


    and f.backtest_biz_id = #{criteria.backtestBizId}


    and f.feedback_action = #{criteria.feedbackAction}

mapper.select:
select f.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
